// 正则转义
function escapeRegExp(str) {
  return str.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
}

// 统一替换函数
function replaceAll(text) {
  if (typeof text !== 'string') return text;

  // 侮辱性组合：丑三八、傻娘们、臭八婆 → 清空
  const insultPattern = /[丑臭傻蠢烂恶疯泼贱肥破脏坏龟老死]+\s*(娘们|三八|八婆|婆娘|马子)/giu;
  text = text.replace(insultPattern, '');

  // ========== 所有带“妈/娘”脏话全部清空 ==========
  text = text.replace(/\b(你|他|她|它)(妈的|娘的)\b/g, '');
  text = text.replace(/\b(你|他|她|它)(妈|娘)\b/g, '');
  // =================================================

  // 独立「操」只替换脏话，不影响 操心、操作、操弄
  text = text.replace(/(?<![\u4e00-\u9fa5])操(?![\u4e00-\u9fa5])/giu, '劁');

  // 独立「我操」替换
  text = text.replace(/(?<![\u4e00-\u9fa5])我操(?![\u4e00-\u9fa5])/giu, '我劁');

  // 单独“三八”清空，避开节日、数字
  text = text.replace(/\b三八\b(?!妇女节)/gu, '');

  // 其余正常替换（长词优先）
  const keys = Object.keys(replaceMap)
    .sort((a, b) => b.length - a.length);

  const normalPattern = new RegExp(keys.map(escapeRegExp).join('|'), 'gmu');
  text = text.replace(normalPattern, match => replaceMap[match] ?? match);

  return text;
}

// 输入框实时替换
document.addEventListener('input', (e) => {
  const el = e.target;
  if ((el.tagName === 'INPUT' || el.tagName === 'TEXTAREA') &&
      (el.classList.contains('chat-input') || el.id.includes('chat-input'))) {
    const oldVal = el.value;
    const newVal = replaceAll(oldVal);
    if (oldVal !== newVal) {
      el.value = newVal;
      const pos = el.selectionStart;
      el.selectionStart = el.selectionEnd = pos;
    }
  }
}, true);

// AI 输出替换
if (typeof eventOn === 'function') {
  eventOn(tavern_events.MESSAGE_RECEIVED, async (mid) => {
    try {
      const msgs = getChatMessages(mid);
      if (!msgs.length || msgs[0].role !== 'assistant') return;
      const orig = msgs[0].message;
      const fixed = replaceAll(orig);
      if (orig !== fixed) {
        await setChatMessages([{ message_id: mid, message: fixed }], { refresh: 'affected' });
      }
    } catch (err) {}
  });

  eventOn(tavern_events.MESSAGE_EDITED, async (mid) => {
    try {
      const msgs = getChatMessages(mid);
      if (!msgs.length) return;
      const orig = msgs[0].message;
      const fixed = replaceAll(orig);
      if (orig !== fixed) {
        await setChatMessages([{ message_id: mid, message: fixed }], { refresh: 'affected' });
      }
    } catch (err) {}
  });

  eventOn(tavern_events.APP_READY, async () => {
    try {
      const last = getLastMessageId();
      if (last < 0) return;
      const all = getChatMessages(`0-${last}`);
      const updates = all.map(m => {
        const fixed = replaceAll(m.message);
        return m.message !== fixed ? { message_id: m.message_id, message: fixed } : null;
      }).filter(Boolean);
      if (updates.length) {
        await setChatMessages(updates, { refresh: 'all' });
      }
    } catch (err) {}
  });
}

